  /**
   * Subscribe to events: 'tokenReceived', 'tokenExpired', 'authError'
   */
  on(event, callback) {
    if (this._eventListeners[event]) {
      this._eventListeners[event].push(callback);
    }
    return this; // Allow chaining
  }

