/**
 * Custom error class for OAuth-related errors
 */
class OAuthError extends Error {
  constructor(message, code, response = null) {
    super(message);
    this.name = 'OAuthError';
    this.code = code;
    this.response = response;
  }
}

// --- Usage Example ---

// Initialize the OAuth client
const oauthClient = new OAuthImplicitClient({
  clientId: 'your-client-id',
  authorizationEndpoint: 'https://auth.example.com/oauth/authorize',
  redirectUri: window.location.origin + '/callback',
  scope: 'read write profile',
  apiBaseUrl: 'https://api.example.com/v1',
});

// Set up event listeners
oauthClient.on('tokenReceived', (tokenInfo) => {
  console.log('Token received!', tokenInfo);
  // Update UI to show authenticated state
  document.getElementById('login-btn').style.display = 'none';
  document.getElementById('app-content').style.display = 'block';
  loadUserProfile();
});

oauthClient.on('tokenExpired', () => {
  console.log('Token expired! Please re-authenticate.');
  // Update UI to show unauthenticated state
  document.getElementById('login-btn').style.display = 'block';
  document.getElementById('app-content').style.display = 'none';
  alert('Your session has expired. Please log in again.');
});

oauthClient.on('authError', (error) => {
  console.error('Authentication error:', error);
  alert(`Authentication failed: ${error.error_description || error.error}`);
});

// Login button handler
function handleLogin() {
  oauthClient.authorize();
}

// Example API calls
async function loadUserProfile() {
  try {
    const profile = await oauthClient.get('/user/profile');
    console.log('User profile:', profile);
    document.getElementById('user-name').textContent = profile.name;
    document.getElementById('user-email').textContent = profile.email;
  } catch (error) {
    if (error.code === 'token_expired') {
      oauthClient.authorize(); // Re-authenticate
    } else {
      console.error('Failed to load profile:', error);
    }
  }
}

async function updateUserProfile(data) {
  try {
    const result = await oauthClient.put('/user/profile', data);
    console.log('Profile updated:', result);
    return result;
  } catch (error) {
    console.error('Failed to update profile:', error);
    throw error;
  }
}

async function fetchDashboardData() {
  try {
    const [stats, notifications, recentActivity] = await Promise.all([
      oauthClient.get('/dashboard/stats'),
      oauthClient.get('/notifications?limit=5'),
      oauthClient.get('/activity/recent'),
    ]);

    return { stats, notifications, recentActivity };
  } catch (error) {
    console.error('Failed to load dashboard:', error);
    throw error;
  }
}

// Logout handler
function handleLogout() {
  oauthClient.logout('https://auth.example.com/oauth/logout');
}

// Check authentication state on page load
function initApp() {
  if (oauthClient.isAuthenticated()) {
    console.log('User is authenticated. Token expires in', oauthClient.getTokenRemainingTime(), 'seconds');
    document.getElementById('login-btn').style.display = 'none';
    document.getElementById('app-content').style.display = 'block';
    loadUserProfile();
  } else {
    console.log('User is not authenticated.');
    document.getElementById('login-btn').style.display = 'block';
    document.getElementById('app-content').style.display = 'none';
  }
}

